mapper.select:
SELECT no, user_id, id, start_at, end_at, status, created_at, updated_at
FROM tutor_availability
WHERE user_id = #{userId}
  AND start_at < #{endDate}
  AND end_at > #{startDate}
ORDER BY start_at

mapper.update:
UPDATE tutor_availability
SET status = #{status}
WHERE id = #{id}

UPDATE tutor_availability
SET start_at = #{startAt},
    end_at = #{endAt},
    status = #{status}
WHERE id = #{id}

UPDATE tutor_availability
SET status = #{status}
WHERE id IN

    #{id}

mapper.delete:
DELETE ta
FROM tutor_availability ta
LEFT JOIN booking b
       ON b.availability_id = ta.id
      AND b.canceled_at IS NULL
WHERE ta.user_id = #{userId}
  AND ta.start_at >= #{startDate}
  AND ta.end_at <= #{endDate}
  AND ta.status = 'OPEN'
  AND b.id IS NULL
